import { ethers } from "ethers";

const RPC_URL = process.env.RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID";
const PRIVATE_KEY = process.env.PRIVATE_KEY || "YOUR_PRIVATE_KEY";

if (!PRIVATE_KEY || PRIVATE_KEY === "YOUR_PRIVATE_KEY") {
  throw new Error("Missing PRIVATE_KEY environment variable");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

export async function getNetwork() {
  return await provider.getNetwork();
}

export async function getWalletAddress() {
  return await wallet.getAddress();
}

export async function getEthBalance(address = wallet.address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

export async function sendETH(to, amountInEth, options = {}) {
  if (!ethers.isAddress(to)) {
    throw new Error("Invalid recipient address");
  }

  const tx = {
    to,
    value: ethers.parseEther(String(amountInEth)),
    gasLimit: options.gasLimit ? BigInt(options.gasLimit) : undefined,
    gasPrice: options.gasPrice ? ethers.parseUnits(String(options.gasPrice), "gwei") : undefined,
    nonce: options.nonce,
    data: options.data || "0x",
  };

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    gasLimit: response.gasLimit?.toString(),
    gasPrice: response.gasPrice?.toString(),
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
  };
}

export function getContract(contractAddress, abi, signerOrProvider = wallet) {
  if (!ethers.isAddress(contractAddress)) {
    throw new Error("Invalid contract address");
  }
  return new ethers.Contract(contractAddress, abi, signerOrProvider);
}

export async function callContractRead(contractAddress, abi, method, args = []) {
  const contract = getContract(contractAddress, abi, provider);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }
  return await contract[method](...args);
}

export async function sendContractTransaction(contractAddress, abi, method, args = [], options = {}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }

  const txOverrides = {};
  if (options.value !== undefined) txOverrides.value = ethers.parseEther(String(options.value));
  if (options.gasLimit !== undefined) txOverrides.gasLimit = BigInt(options.gasLimit);
  if (options.gasPrice !== undefined) txOverrides.gasPrice = ethers.parseUnits(String(options.gasPrice), "gwei");
  if (options.nonce !== undefined) txOverrides.nonce = options.nonce;

  const response = await contract[method](...args, txOverrides);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    gasLimit: response.gasLimit?.toString(),
    gasPrice: response.gasPrice?.toString(),
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
  };
}

export async function estimateEthTransferGas(to, amountInEth) {
  const gas = await provider.estimateGas({
    from: wallet.address,
    to,
    value: ethers.parseEther(String(amountInEth)),
  });
  return gas.toString();
}

export async function estimateContractGas(contractAddress, abi, method, args = [], options = {}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (!contract[method]?.estimateGas) {
    throw new Error(`Cannot estimate gas for method ${method}`);
  }

  const txOverrides = {};
  if (options.value !== undefined) txOverrides.value = ethers.parseEther(String(options.value));

  const gas = await contract[method].estimateGas(...args, txOverrides);
  return gas.toString();
}

export async function getTransaction(txHash) {
  return await provider.getTransaction(txHash);
}

export async function getTransactionReceipt(txHash) {
  return await provider.getTransactionReceipt(txHash);
}

export async function getCurrentGasPrice() {
  const feeData = await provider.getFeeData();
  return {
    gasPrice: feeData.gasPrice?.toString() || null,
    maxFeePerGas: feeData.maxFeePerGas?.toString() || null,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas?.toString() || null,
  };
}

const erc20Abi = [
  "function balanceOf(address owner) view returns (uint256)",
  "function transfer(address to, uint256 value) returns (bool)",
  "function decimals() view returns (uint8)",
  "function symbol() view returns (string)",
];

export async function getErc20Balance(tokenAddress, ownerAddress = wallet.address) {
  const contract = getContract(tokenAddress, erc20Abi, provider);
  const [balance, decimals, symbol] = await Promise.all([
    contract.balanceOf(ownerAddress),
    contract.decimals(),
    contract.symbol(),
  ]);

  return {
    raw: balance.toString(),
    formatted: ethers.formatUnits(balance, decimals),
    decimals,
    symbol,
  };
}

export async function sendErc20(tokenAddress, to, amount, options = {}) {
  const contract = getContract(tokenAddress, erc20Abi, wallet);
  const decimals = await contract.decimals();
  const parsedAmount = ethers.parseUnits(String(amount), decimals);

  const response = await contract.transfer(
    to,
    parsedAmount,
    {
      gasLimit: options.gasLimit ? BigInt(options.gasLimit) : undefined,
      gasPrice: options.gasPrice ? ethers.parseUnits(String(options.gasPrice), "gwei") : undefined,
      nonce: options.nonce,
    }
  );

  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
  };
}

export default {
  provider,
  wallet,
  getNetwork,
  getWalletAddress,
  getEthBalance,
  sendETH,
  getContract,
  callContractRead,
  sendContractTransaction,
  estimateEthTransferGas,
  estimateContractGas,
  getTransaction,
  getTransactionReceipt,
  getCurrentGasPrice,
  getErc20Balance,
  sendErc20,
};